    def test_loader_ignores_non_object_split_shard_payloads(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            (root / "demo.comments").mkdir()
            (root / "demo.runs").mkdir()
            (root / "demo.json").write_text(
                json.dumps(
                    {
                        "version": 1,
                        "storage": "split",
                        "commentFiles": ["demo.comments/comments-0001.json", "demo.comments/comments-0002.json"],
                        "runFiles": ["demo.runs/runs-0001.json", "demo.runs/runs-0002.json"],
                    }
                ),
                encoding="utf-8",
            )
            (root / "demo.comments" / "comments-0001.json").write_text(
                json.dumps(["bad comment shard"]),
                encoding="utf-8",
            )
            (root / "demo.comments" / "comments-0002.json").write_text(
                json.dumps({"comments": [{"message": "valid comment"}]}),
                encoding="utf-8",
            )
            (root / "demo.runs" / "runs-0001.json").write_text(json.dumps("bad run shard"), encoding="utf-8")
            (root / "demo.runs" / "runs-0002.json").write_text(
                json.dumps({"runs": [{"at": "valid-run"}]}),
                encoding="utf-8",
            )

            corpus = CorpusLoader(root / "demo.json").load()

        self.assertEqual(corpus.comments, [{"message": "valid comment"}])
        self.assertEqual(corpus.runs, [{"at": "valid-run"}])

    def test_loader_builds_from_js_json_payload_contract(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            corpus_path = root / "payload-corpus.json"
            corpus_path.write_text(
                json.dumps({"version": 1, "comments": [{"message": "payload comment"}], "runs": [{"at": "payload-run"}]}),
                encoding="utf-8",
            )

            loaded = CorpusLoader.load_from_payload({"corpusPath": str(corpus_path)})
            fallback = CorpusLoader.load_from_payload(
                {
                    "path": str(root / "missing.json"),
                    "fallback": {"version": 1, "comments": [{"message": "fallback"}], "runs": [{"at": "fallback-run"}]},
                }
            )

        self.assertEqual(loaded.comments, [{"message": "payload comment"}])
        self.assertEqual(loaded.runs, [{"at": "payload-run"}])
        self.assertEqual(fallback.comments, [{"message": "fallback"}])
        self.assertEqual(fallback.runs, [{"at": "fallback-run"}])

    def test_loader_accepts_inline_js_json_payload_contract(self):
        loaded = CorpusLoader.load_from_payload(
            {
                "corpus": {
                    "comments": [{"message": "inline comment"}, "plain text comment"],
                    "runs": [{"at": "inline-run"}, "ignored"],
                    "manifest": {"storage": "inline", "source": "payload"},
                }
            }
        )

        self.assertEqual(loaded.manifest["storage"], "inline")
        self.assertEqual(loaded.manifest["source"], "payload")
        self.assertEqual(loaded.comments, [{"message": "inline comment"}, {"message": "plain text comment"}])
        self.assertEqual(loaded.runs, [{"at": "inline-run"}])

    def test_loader_normalizes_inline_plain_text_comment_payloads(self):
        loaded = CorpusLoader.load_from_payload(
            {
                "corpus": {
                    "comments": [
                        "\u72d7\u5934\u4fdd\u547d[doge]",
                        {"text": "\u5efa\u8bae\u67e5\u67e5\u8d44\u6599", "source": "tieba"},
                        "",
                    ],
                    "runs": [],
                }
            }
        )

        self.assertEqual(
            loaded.comments,
            [
                {"message": "\u72d7\u5934\u4fdd\u547d[doge]"},
                {"text": "\u5efa\u8bae\u67e5\u67e5\u8d44\u6599", "source": "tieba"},
            ],
        )

