        self.assertEqual(loaded["videoCount"], 3)
        self.assertEqual(loaded["runCount"], 2)
        self.assertEqual(loaded["tags"], tags)
        self.assertEqual(loaded["videos"], videos)
        self.assertEqual(loaded["runs"], runs)

