    def test_comment_coverage_classifier_matches_core_js_modes(self):
        dictionary = {
            "entries": [
                {"term": "\u7f51\u76d8\u89c1", "family": "evasion", "aliases": ["\u94fe\u63a5\u81ea\u53d6"]},
                {"term": "\u61c2\u7684\u90fd\u61c2", "family": "evasion"},
            ]
        }
        classifier = CommentCoverageClassifier()

        keyword = classifier.classify(dictionary, {"message": "\u7f51\u76d8\u89c1\uff0c\u61c2\u7684\u90fd\u61c2"})
        neutral = classifier.classify(dictionary, {"message": "\u8def\u8fc7\u770b\u770b"})
        diagnostic = classifier.classify(dictionary, {"message": "discover: HTTP 403 from https://api.bilibili.com/x"})
        unsupported = classifier.classify(dictionary, {"message": "plain ascii only"})

        self.assertEqual(keyword["mode"], "keyword")
        self.assertEqual([hit["term"] for hit in keyword["hits"]], ["\u7f51\u76d8\u89c1", "\u61c2\u7684\u90fd\u61c2"])
        self.assertEqual(neutral["mode"], "neutral")
        self.assertEqual(diagnostic["reason"], "scrape diagnostic line, not user speech")
        self.assertFalse(unsupported["covered"])

    def test_comment_coverage_classifier_reads_scraper_comment_text_fields(self):
        dictionary = {"entries": [{"term": "\u72d7\u5934", "family": "evasion"}, {"term": "\u67e5\u8d44\u6599", "family": "evidence"}]}
        classifier = CommentCoverageClassifier()

        comment_text = classifier.classify(dictionary, {"commentText": "\u72d7\u5934\u4fdd\u547d[doge]"})
        combined_text = classifier.classify(dictionary, {"combinedText": "\u5efa\u8bae\u67e5\u67e5\u8d44\u6599"})
        text = classifier.classify(dictionary, {"text": "\u666e\u901a\u8bc4\u8bba"})

        self.assertEqual(comment_text["mode"], "keyword")
        self.assertEqual(combined_text["mode"], "keyword")
        self.assertEqual(text["mode"], "neutral")

    def test_comment_coverage_classifier_treats_emoji_only_comments_as_neutral_tone(self):
        classifier = CommentCoverageClassifier()

        emoji = classifier.classify({"entries": []}, "\U0001f602\U0001f602\U0001f602")
        emoticon = classifier.classify({"entries": []}, "^_^")

        self.assertTrue(emoji["covered"])
        self.assertEqual(emoji["mode"], "neutral")
        self.assertEqual(emoji["reason"], "emoji/emoticon-only comment; analyzable as neutral tone without lexical risk term")
        self.assertTrue(emoticon["covered"])
        self.assertEqual(emoticon["mode"], "neutral")

